import{_ as a,o as i,c as e,a2 as r}from"./chunks/framework.Crpw6aS5.js";const b=JSON.parse('{"title":"2011年巴菲特致股东信核心总结","description":"","frontmatter":{},"headers":[],"relativePath":"01_letters/2011年/核心总结.md","filePath":"01_letters/2011年/核心总结.md"}'),t={name:"01_letters/2011年/核心总结.md"};function o(h,l,n,u,d,s){return i(),e("div",null,[...l[0]||(l[0]=[r('<h1 id="_2011年巴菲特致股东信核心总结" tabindex="-1">2011年巴菲特致股东信核心总结 <a class="header-anchor" href="#_2011年巴菲特致股东信核心总结" aria-label="Permalink to &quot;2011年巴菲特致股东信核心总结&quot;">​</a></h1><h2 id="业绩表现" tabindex="-1">业绩表现 <a class="header-anchor" href="#业绩表现" aria-label="Permalink to &quot;业绩表现&quot;">​</a></h2><ul><li>每股账面价值增长4.6%</li><li>47年复合年增长率19.8%</li><li>连续九年实现承保盈利，累计约170亿美元</li><li>浮存金从410亿美元增至700亿美元</li></ul><h2 id="重大人事变动" tabindex="-1">重大人事变动 <a class="header-anchor" href="#重大人事变动" aria-label="Permalink to &quot;重大人事变动&quot;">​</a></h2><h3 id="投资管理传承" tabindex="-1">投资管理传承 <a class="header-anchor" href="#投资管理传承" aria-label="Permalink to &quot;投资管理传承&quot;">​</a></h3><ul><li>Todd Combs和Ted Weschler加入投资管理团队</li><li>各管理数十亿美元资产</li><li>具备智慧、判断力和品格，可在巴菲特和芒格不在时管理全部投资组合</li></ul><h3 id="ceo继任安排" tabindex="-1">CEO继任安排 <a class="header-anchor" href="#ceo继任安排" aria-label="Permalink to &quot;CEO继任安排&quot;">​</a></h3><ul><li>董事会已确定CEO接任人选</li><li>有两位出色的备选候选人</li><li>巴菲特98%净资产配置在伯克希尔股票</li></ul><h2 id="重大收购" tabindex="-1">重大收购 <a class="header-anchor" href="#重大收购" aria-label="Permalink to &quot;重大收购&quot;">​</a></h2><h3 id="lubrizol收购" tabindex="-1">Lubrizol收购 <a class="header-anchor" href="#lubrizol收购" aria-label="Permalink to &quot;Lubrizol收购&quot;">​</a></h3><ul><li>9月16日收购，全球添加剂及特种化学品生产商</li><li>税前利润从2004年的1.47亿美元增至10.85亿美元</li><li>已完成三笔补强收购，耗资4.93亿美元</li></ul><h2 id="五大业务板块表现" tabindex="-1">五大业务板块表现 <a class="header-anchor" href="#五大业务板块表现" aria-label="Permalink to &quot;五大业务板块表现&quot;">​</a></h2><ul><li>BNSF、Iscar、Lubrizol、Marmon、MidAmerican Energy</li><li>合计创造超过90亿美元税前利润</li><li>2012年预计合计利润超过100亿美元</li></ul><h2 id="资本支出" tabindex="-1">资本支出 <a class="header-anchor" href="#资本支出" aria-label="Permalink to &quot;资本支出&quot;">​</a></h2><ul><li>2011年投入82亿美元固定资产和设备</li><li>95%投放在美国</li><li>2012年将再次创下纪录</li></ul><h2 id="投资组合变化" tabindex="-1">投资组合变化 <a class="header-anchor" href="#投资组合变化" aria-label="Permalink to &quot;投资组合变化&quot;">​</a></h2><h3 id="四大持仓" tabindex="-1">四大持仓 <a class="header-anchor" href="#四大持仓" aria-label="Permalink to &quot;四大持仓&quot;">​</a></h3><ul><li>美国运通13.0%、可口可乐8.8%、IBM 5.5%、富国银行7.6%</li><li>新增IBM和美国银行投资</li><li>美国银行：50亿美元优先股+7亿股认股权证</li></ul><h3 id="未分配收益的价值" tabindex="-1">未分配收益的价值 <a class="header-anchor" href="#未分配收益的价值" aria-label="Permalink to &quot;未分配收益的价值&quot;">​</a></h3><ul><li>四大公司账面未报告收益24亿美元</li><li>留存收益将用于股票回购和商业机会</li><li>十年后四大公司可能产生70亿美元收益</li></ul><h2 id="投资失误与挫折" tabindex="-1">投资失误与挫折 <a class="header-anchor" href="#投资失误与挫折" aria-label="Permalink to &quot;投资失误与挫折&quot;">​</a></h2><h3 id="energy-future-holdings" tabindex="-1">Energy Future Holdings <a class="header-anchor" href="#energy-future-holdings" aria-label="Permalink to &quot;Energy Future Holdings&quot;">​</a></h3><ul><li>约20亿美元债券投资，判断天然气价格错误</li><li>累计减记13.9亿美元</li></ul><h3 id="固定收益投资赎回" tabindex="-1">固定收益投资赎回 <a class="header-anchor" href="#固定收益投资赎回" aria-label="Permalink to &quot;固定收益投资赎回&quot;">​</a></h3><ul><li>瑞士再保险、高盛、通用电气优先股被赎回</li><li>损失约12亿美元税前收益</li></ul><h3 id="房地产相关业务" tabindex="-1">房地产相关业务 <a class="header-anchor" href="#房地产相关业务" aria-label="Permalink to &quot;房地产相关业务&quot;">​</a></h3><ul><li>五家公司税前利润从2006年18亿美元降至5.13亿美元</li><li>就业人数从58,769人降至43,315人</li></ul><h2 id="关键投资理念" tabindex="-1">关键投资理念 <a class="header-anchor" href="#关键投资理念" aria-label="Permalink to &quot;关键投资理念&quot;">​</a></h2><h3 id="股票回购原则" tabindex="-1">股票回购原则 <a class="header-anchor" href="#股票回购原则" aria-label="Permalink to &quot;股票回购原则&quot;">​</a></h3><ol><li>公司有充足资金满足运营和流动性需求</li><li>股票以内在价值的实质折扣出售</li></ol><ul><li>伯克希尔以不超过账面价值110%回购</li></ul><h3 id="投资者的基本选择" tabindex="-1">投资者的基本选择 <a class="header-anchor" href="#投资者的基本选择" aria-label="Permalink to &quot;投资者的基本选择&quot;">​</a></h3><p><strong>三类主要投资：</strong></p><ol><li><p><strong>货币计价资产</strong></p><ul><li>被认为是&quot;安全&quot;的，实际最危险</li><li>过去一个世纪在许多国家摧毁购买力</li><li>美元自1965年贬值86%</li></ul></li><li><p><strong>无生产力资产</strong></p><ul><li>黄金是典型代表</li><li>不产生任何东西，依赖他人以更高价格购买</li><li>17万吨黄金价值9.6万亿美元，可购买全美农田+16个埃克森美孚</li></ul></li><li><p><strong>生产性资产</strong></p><ul><li>企业、农场、房地产</li><li>在通胀时期能保留购买力</li><li>产出能力是关键</li></ul></li></ol><h3 id="投资定义" tabindex="-1">投资定义 <a class="header-anchor" href="#投资定义" aria-label="Permalink to &quot;投资定义&quot;">​</a></h3><ul><li>投资是现在放弃消费，以便未来消费更多</li><li>风险用购买力损失概率衡量，不是beta</li><li>应选择生产性资产</li></ul><h2 id="保险业务价值" tabindex="-1">保险业务价值 <a class="header-anchor" href="#保险业务价值" aria-label="Permalink to &quot;保险业务价值&quot;">​</a></h2><h3 id="浮存金的内在价值" tabindex="-1">浮存金的内在价值 <a class="header-anchor" href="#浮存金的内在价值" aria-label="Permalink to &quot;浮存金的内在价值&quot;">​</a></h3><ul><li>账面价值将浮存金全额扣除作为负债</li><li>实际应视为循环基金</li><li>无成本持久的浮存金价值远超账面记录</li><li>保险商誉真实经济价值远超账面价值</li></ul><h3 id="保险公司评估" tabindex="-1">保险公司评估 <a class="header-anchor" href="#保险公司评估" aria-label="Permalink to &quot;保险公司评估&quot;">​</a></h3><ul><li>商誉成本与真实价值无关</li><li>若产生持续承保亏损，任何商誉应视为毫无价值</li><li>伯克希尔保险商誉真实价值远超历史账面价值</li></ul><h2 id="房地产市场分析" tabindex="-1">房地产市场分析 <a class="header-anchor" href="#房地产市场分析" aria-label="Permalink to &quot;房地产市场分析&quot;">​</a></h2><h3 id="泡沫成因" tabindex="-1">泡沫成因 <a class="header-anchor" href="#泡沫成因" aria-label="Permalink to &quot;泡沫成因&quot;">​</a></h3><ul><li>过度建造住房单元超过家庭形成</li><li>家庭形成在衰退初期放缓</li><li>供需等式已逆转：每天创造家庭多于住房单元</li></ul><h3 id="复苏预期" tabindex="-1">复苏预期 <a class="header-anchor" href="#复苏预期" aria-label="Permalink to &quot;复苏预期&quot;">​</a></h3><ul><li>家庭形成必然与住房单元匹配</li><li>荷尔蒙最终占上风</li><li>未来每年将建造100万套以上住宅</li></ul><h2 id="美国经济前景" tabindex="-1">美国经济前景 <a class="header-anchor" href="#美国经济前景" aria-label="Permalink to &quot;美国经济前景&quot;">​</a></h2><ul><li>1776年以来最好的日子还在前方</li><li>美国的制度仍然充满活力</li><li>悲观者忽视了人类潜力和美国制度</li></ul>',48)])])}const q=a(t,[["render",o]]);export{b as __pageData,q as default};
